-- {"operators": "INNER_JOIN,AGGREGATE,WINDOW", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,HISTORY", "openivm_verified": true}
SELECT c.C_ID, h.H_AMOUNT, AVG(h.H_AMOUNT) OVER (PARTITION BY c.C_ID) AS part_avg, h.H_AMOUNT - AVG(h.H_AMOUNT) OVER (PARTITION BY c.C_ID) AS diff FROM CUSTOMER c JOIN HISTORY h ON c.C_ID = h.H_C_ID AND c.C_W_ID = h.H_C_W_ID;
